"""Entry point for python -m agentpulse."""

import argparse
import logging
import logging.handlers
from pathlib import Path


def _configure_logging(*, log_file: Path, log_level: str) -> None:
    """Set up root logger with rotating file handler."""
    level = getattr(logging, log_level, logging.INFO)

    log_file.parent.mkdir(parents=True, exist_ok=True)
    handler = logging.handlers.RotatingFileHandler(
        log_file,
        maxBytes=2 * 1024 * 1024,
        backupCount=3,
        encoding="utf-8",
    )
    handler.setFormatter(
        logging.Formatter("%(asctime)s %(levelname)s %(name)s: %(message)s")
    )
    handler.setLevel(level)

    root = logging.getLogger()
    root.setLevel(level)
    root.addHandler(handler)


def main() -> None:
    """Start the AgentPulse service."""
    import uvicorn

    from agentpulse.config import get_settings, set_config_path

    parser = argparse.ArgumentParser(description="AgentPulse service")
    parser.add_argument(
        "--config",
        type=Path,
        required=True,
        help="Path to config JSON file",
    )
    args = parser.parse_args()

    set_config_path(config_path=args.config)
    settings = get_settings()

    _configure_logging(log_file=settings.log_file, log_level=settings.log_level)

    uvicorn.run(
        "agentpulse.app:create_app",
        factory=True,
        host=settings.host,
        port=settings.port,
        log_level=settings.log_level.lower(),
    )


if __name__ == "__main__":
    main()
